#define ROWS 10
#define NUM_MAPS 6
#define BALL_SIZE  8
#define SPEED 8

// offset to center the 200x200 maze on the 320x240 screen
#define MAP_OFFSET_X  ((SCREEN_W - COLS*TILE) / 2)   // = 60
#define MAP_OFFSET_Y  ((SCREEN_H - ROWS*TILE) / 2)   // = 20

// color definitions
#define WHITE  0xFFFF
#define RED  0xF800
#define GREEN 0x07E0
#define BLUE 0x001F
#define YELLOW 0xFFE0
#define CYAN 0x07FF
#define ORANGE 0xFD20

#define COL_BG 0x0000   // black background


#define COL_BG         0x0000   // black background
#define COL_WALL_OUTER 0x4208   // dark gray wall border
#define COL_WALL_CORE 0xFFFF   // white wall face
#define COL_WALL_SHINE 0xAD55   // light blue-gray wall highlight

// player ball
#define COL_PLAYER 0xF81F   // pink
#define COL_AGENT  0x001F   // blue

// target
#define COL_TARGET 0x07FF


// GAME MODES 
#define MODE_FREE   -1   // player only
#define MODE_RANDOM  0
#define MODE_DFS     1
#define MODE_RL      2

volatile int game_mode = MODE_FREE;

// DFS STORAGE 
#define MAX_PATH 200

int dfs_path[MAX_PATH];
int dfs_len = 0;
int dfs_index = 0;



// hardware interval timer at 0xFF202000
// runs at 100MHz so 100,000,000 ticks = 1 second
// we set it to fire every 1 second directly
#define TIMER_BASE       0xFF202000
#define TIMER_TICKS_1SEC 100000000   // 100MHz * 1 second

void timer_hw_init(void) {
    volatile int *timer = (int *) TIMER_BASE;
    *(timer + 2) = TIMER_TICKS_1SEC & 0xFFFF;         // low 16 bits of start value
    *(timer + 3) = (TIMER_TICKS_1SEC >> 16) & 0xFFFF; // high 16 bits
    *(timer + 1) = 0b0111;   // START + CONT + ITO (interrupt enable optional)
}

// returns 1 exactly once per second, 0 otherwise
int timer_hw_tick(void) {
    volatile int *timer = (int *) TIMER_BASE;
    if (*(timer + 0) & 0x1) {   // TO (timeout) flag set
        *(timer + 0) = 0;        // clear flag by writing any value
        return 1;
    }
    return 0;
}


// round timer globals — must be declared before draw_map, reset_round, and main
#define ROUND_TIME_SEC  30
int round_timer_sec  = ROUND_TIME_SEC;

// only needed if you kept the software timer fallback, remove if using hardware timer
int timer_tick_count = 0;

// position for timer display on screen — top right area
#define TIMER_X  280
#define TIMER_Y   20


// audio --------------------------
#define AUDIO_BASE 0xFF203040
volatile int *audio_ptr = (int *) AUDIO_BASE;

int  *clip_data = 0;
int   clip_len  = 0;
int   clip_pos  = -1;

void trigger_clip(int *data, int len) {
    clip_data = data;
    clip_len  = len;
    clip_pos  = 0;
}

void update_audio(void) {
    if (clip_pos < 0 || clip_pos >= clip_len) {
        clip_pos = -1;
        return;
    }
    int fifospace = *(audio_ptr + 1);
    int wslc = (fifospace >> 24) & 0xFF;
    if (wslc == 0) return;

    int sample = clip_data[clip_pos++];
    *(audio_ptr + 2) = sample;
    *(audio_ptr + 3) = sample;
}




